 1	import React, { FC, PropsWithChildren, Ref, useState } from 'react';
 2	
 3	import { Dropdown, DropdownList, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 4	
 5	type SelectProps = PropsWithChildren<{
 6	  id?: string;
 7	  selected: any;
 8	  toggleContent: Element | React.JSX.Element | string;
 9	}>;
10	
11	const Select: FC<SelectProps> = ({ children, id, selected, toggleContent }) => {
12	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
13	
14	  return (
15	    <Dropdown
16	      id={id}
17	      isOpen={isDropdownOpen}
18	      onOpenChange={setIsDropdownOpen}
19	      onSelect={() => setIsDropdownOpen(false)}
20	      selected={selected}
21	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
22	        <MenuToggle
23	          id={`toggle-${id}`}
24	          isExpanded={isDropdownOpen}
25	          isFullWidth
26	          onClick={() => setIsDropdownOpen(!isDropdownOpen)}
27	          ref={toggleRef}
28	        >
29	          {toggleContent}
30	        </MenuToggle>
31	      )}
32	    >
33	      <DropdownList>{children}</DropdownList>
34	    </Dropdown>
35	  );
36	};
37	
38	export default Select;

